var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"누가 고물 함선 아니랄까 봐 겁나게 흔들리네. 다이브하다 부서지는 거 아냐?","JPN":"オンボロ艦船らしく、 とんでもない揺れだな。ダイブ中に壊れるんじゃないか？","ENG":"That's some serious turbulence. I should've known with this crappy old ride. What if it falls apart during the Dive?","TWN":"這還真是老古董艦船，晃得也太厲害了。不會躍入到一半就碎了吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"재수없는 소리 하지 마. 진짜 그럴 것 같잖아.","JPN":"縁起でもないこと言うな。マジでそうなりそうだから。","ENG":"Don't jinx us like that. It could actually happen.","TWN":"別烏鴉嘴，萬一真的應驗了怎麼辦。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"우...... 우으......","JPN":"う……うぅ……","ENG":"Ugh... Blegh...","TWN":"嗚……嗚哇……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"이게 다이브 멀미구나...... 눈이 핑핑 돌아......","JPN":"これがダイブ酔い……目が回る……","ENG":"So this is what Dive sickness feels like... The entire world is spinning...","TWN":"這就是躍入出現的眩暈啊……兩眼都冒金星了……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니가 걱정하던 게 이래서였을까......?","JPN":"リタお姉ちゃんが心配していたのはこれ……？","ENG":"Is this why Rita was worried?","TWN":"麗塔姐姐擔心的是這個嗎……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"따라오겠다고?","JPN":"ついてくるって？","ENG":"You want to tag along?","TWN":"你要一起去？"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"넹! 언니가 가는데 저도 당연히 가야죠!","JPN":"はいっ！　リタお姉ちゃんが行くなら当然私もついて行かないと！","ENG":"Yup! If you're going, I should be there too!","TWN":"嗯！姐姐去我當然也要去嘍！"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아니. 넌 이면세계가 어떤 곳인지 몰라.","JPN":"いや、お前は裏世界がどんな場所なのか知らないだろ。","ENG":"No. You have no idea what the Counterside is like.","TWN":"不，你不知道異界是個怎樣的地方。"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"비즈니스 모텔에 방 하나 구해 줄 테니 얌전히 기다리고 있어.","JPN":"ビジネスホテルに部屋をとってやるからそこで大人しく待っていろ。","ENG":"I'll get you a room at a business hotel. Just stay put there.","TWN":"我會在商務旅館給你訂個房間，你乖乖等我回來。"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"하지만 윌버 씨한테 기회를 달라고 부탁한 사람은 저잖아요. 모른 척 하긴 싫어요.","JPN":"でもウィルバーさんにチャンスを与えてほしいと頼んだのは私です。責任持って見届けないと。","ENG":"But I'm the one who asked you to give Mr. Wilbur another chance. I can't just send him off without me.","TWN":"但是請求給韋爾伯一次機會的人是我啊。我不想置身事外。"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"하아...... 부모 닮아서 참 고집불통이군......","JPN":"はあ……親に似て頑固だな……","ENG":"Ugh... Stubborn, just like your parents.","TWN":"唉……怎麼跟她父母一樣，都這麼固執……"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"어차피 여기 두고 가도 사고나 치겠지.","JPN":"どうせ置いていってもまた何かやらかしそうだろう。","ENG":"I suppose you'll just get into more trouble if I leave you here.","TWN":"把你留在這裡應該也會惹禍吧。"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"대신 거기선 절대로 설치지 마.","JPN":"連れていく代わりに、そこでは勝手な行動は絶対しないと約束しろ。","ENG":"Fine. But don't do anything you're not told to when we're down there.","TWN":"但你到了那裡，答應我一定不能搗亂。"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그럼요! 당연하죠!","JPN":"はい！　もちろんです！","ENG":"Right on! Of course!","TWN":"當然啦！當然！"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"무섭다...... 이면세계......","JPN":"怖いなぁ……裏世界……","ENG":"I had no idea... the Counterside is this terrifying...","TWN":"異界……好恐怖啊……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_SYS_RUNNING"},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"미안해요, 리타 언니...... 저 먼저 가요...... 히잉......","JPN":"ごめんなさい、リタお姉ちゃん……私……先に逝きます……ひぃん……","ENG":"I'm sorry, Rita... but I think this is it for me... Hngh...","TWN":"對不起，麗塔姐姐……我先走了……嚶嚶……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_Q","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_Q","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L28_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"우으...... 누구...... 세요?","JPN":"うぅ……どなた……ですか？","ENG":"Hngh... Who... are you?","TWN":"嗚……是……誰？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_Q","text":{"KOREA":"이걸 삼키거라. 곧 상태가 호전될지어다.","JPN":"これを飲むがよい。すぐに良くなるだろう。","ENG":"Swallow this. It should alleviate your ailment presently.","TWN":"吃了這個，很快就會好的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"이건...... 멀미약......?","JPN":"これは……酔い止め……？","ENG":"Is this... a motion sickness pill?","TWN":"這是……暈船藥……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"흐아......","JPN":"ふわぁ……","ENG":"Phew...","TWN":"呃啊……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"감사합니다! 금방 멀쩡해졌어요! 약 효과가 엄청 좋네요!","JPN":"ありがとうございます！　本当によくなりました！　すごい効き目の薬ですね！","ENG":"Thank you! I feel much better now! That thing works like magic!","TWN":"謝謝！我等一下就沒事了！這藥的效果真好！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_Q","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"앗! 잠깐만요, 갑옷 씨!","JPN":"あっ！　お待ちください、鎧さん！","ENG":"Oh! Just a minute, Armored Lady!","TWN":"啊！等等，穿鎧甲的先生！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"신경 쓰지 마, 꼬마야.","JPN":"彼は放っておけ、お嬢ちゃん。","ENG":"Don't bother, kid.","TWN":"別多管閒事，小鬼。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"<color=#ffd34c>모르스</color>는 원래 자기 하고 싶은 말만 하기로 유명하거든.","JPN":"<color=#ffd34c>モールス</color>は元々自分が言いたいことしか言わないことで有名だからな。","ENG":"<color=#ffd34c>Mors</color> is notoriously quiet, except when she feels like talking.","TWN":"<color=#ffd34c>死神莫爾斯</color>還是一如往常的自說自話。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"네? 모르스요?","JPN":"はい？　モールス？","ENG":"Sorry? Mors?","TWN":"啊？死神莫爾斯？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"맞아, 모르스. 저 녀석 이름이야.","JPN":"そう、モールス。あいつの名前だ。","ENG":"That's right. Mors. That's her name.","TWN":"沒錯，莫爾斯。就是那傢伙的名字。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"블랙 네트워크에선 가는 곳마다 재앙을 부른다는 녀석으로 유명해.","JPN":"ブラックネットワークでは行く先々に災いをもたらすことで有名だ。","ENG":"In the Dark Network, she's known as someone who brings disaster with her wherever she goes.","TWN":"在黑色網路中，他可是挺出名的！因為他所到之處都會招來災難。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"블랙...... 네트워크?","JPN":"ブラック……ネットワーク？","ENG":"Dark... Network?","TWN":"黑色……網路？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"뭔진 모르겠지만 재앙이라니 너무해요, 착한 분 같은데......","JPN":"よくわからないけど、災いってひどいですね。良い人そうに見えるのに……","ENG":"Whatever that is, that's awful. Shee seems to be a nice lady…","TWN":"雖然不知道是什麼，但說是災難也太過分了吧。他看起來挺善良的……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"하핫. 너 용병이 아니구나? 블랙 네트워크도 모르는 걸 보니.","JPN":"ハハハッ、あんたは傭兵じゃないんだな？　ブラックネットワークも知らないとは。","ENG":"Hah hah. You're not a mercenary, are you? You haven't even heard of the Dark Network.","TWN":"哈哈，原來你不是傭兵啊。連黑色網路都不知道。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아, 네. 전 리타 언니 조수라서 따라온 거거든요.","JPN":"あ、はい。私はリタお姉ちゃんの助手としてついてきたんです。","ENG":"Oh, right. I tagged along as Rita's assistant.","TWN":"啊，是的。我是作為麗塔姐姐的助手一起來的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"제 이름은 대시예요. 아저씨는요?","JPN":"私の名前はダッシュです。おじさんは？","ENG":"My name is Dash. How about you?","TWN":"我叫黛西。叔叔你呢？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"그냥 대장이라고 불러. 여기 타고 있는 용병들 중 대부분이 내 친구들이거든.","JPN":"俺は隊長でいい。ここに乗っている傭兵のほとんどは俺の仲間でな。","ENG":"Just call me Captain. Most of these guys here are my buddies.","TWN":"就叫我隊長吧，這裡的大部分傭兵都是我的朋友。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"우와, 대단해! 저희 사무소는 저까지 합쳐도 세 명밖에 안 되는데!","JPN":"うわぁ、すごいですね！　うちの事務所は私含めて3人しかいないのに！","ENG":"Wow, that's impressive! My workplace only has three folks... including me!","TWN":"哇，真了不起！我們事務所就算加上我也只有三個人！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"아직 학생인 것 같은데...... 사무소라고?","JPN":"まだ学生に見えるけど……事務所って？","ENG":"Aren't you just a kid? Did you just say workplace?","TWN":"你好像還是個學生……什麼事務所？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"넹! 호라이즌 파이낸스에서 일하고 있어요!","JPN":"はいっ！　ホライズン・ファイナンスで働いてるんです！","ENG":"Yup! I work for Horizon Finance!","TWN":"嗯！我在地平線金融工作！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"그 지독하다는 사채업자들이랑? 아니, 대체 왜?","JPN":"あの悪名高い闇金業者で？　いや、どうして？","ENG":"Those notorious loan sharks? Why on earth would you do that?","TWN":"傳聞中惡毒的高利貸公司？你為什麼會在那裡？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"부모님이 예전에 대표님한테 빚을 많이 지셨거든요. 그래서 제가 대신 갚는 중이에요.","JPN":"親が昔、代表にかなり借金しちゃって。それで私が代わりに返済してるんです。","ENG":"My parents ended up owing the boss a lot of money back in the day. So I'm paying it off on their behalf.","TWN":"我父母之前欠了BOSS很多債款。所以我在代替他們還債。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"세상에...... 아무리 돈에 미쳤어도 그렇지 너무하구만.","JPN":"そんな……いくら金に目がないと言えこんな子どもを……ひどい話だな。","ENG":"Goodness... No matter how crazy they are about money, they shouldn't make a kid like you do such a thing!","TWN":"天啊……再怎麼財迷心竅，這也太過分了吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"잡담도 좋지만 조금은 조용히 해 주시죠. 연구에 방해되지 않습니까.","JPN":"雑談はいいですが、今は静かにしてください。研究の邪魔です。","ENG":"I appreciate you're all getting along, but could you please keep it down? I'm trying to focus on my research.","TWN":"你們聊天可不可以小聲一些，妨礙到我的研究了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"이런, 죄송합니다. 선생님. 저희가 좀 시끄러웠죠?","JPN":"おっと、すみません先生。ちょっと声がデカかったですね。","ENG":"Oh, sorry about that, Doc. We got a bit chatty, didn't we?","TWN":"哎呀，對不起，先生。我們吵到你了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"흠......","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"뭐, 세기의 대발견을 앞두고 이런 일에 일일이 화내기도 그렇죠.","JPN":"まあ、世紀の大発見を前にして、これくらいのことにいちいち怒るのはよくないですね。","ENG":"Well, I suppose I shouldn't be so touchy when I'm about to make the discovery of the century.","TWN":"世紀最大的發現就近在咫尺，我也不想因為這些小事生氣。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"목소리만 좀 낮추세요.","JPN":"声だけちょっと抑えてくださいね。","ENG":"Just try to keep your voice low if you can.","TWN":"只要稍微小聲一點就可以了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그러고 보니 사무소에서도 세기의 대발견이 될 거라고 하셨죠? 왜 그런 거예요?","JPN":"そういえば事務所でも世紀の大発見になるって言ってましたね。どういうことですか？","ENG":"You mentioned that it's going to be great discovery back at the office too, didn't you? How come?","TWN":"您在事務所的時候也說是世紀大發現吧？為什麼呢？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"호오, 역시 관심이 있었군요. 그 돈만 밝히는 사채업자들과는 다르게요.","JPN":"ほう、あの金にしか興味ない闇金業者と違って、僕の話をちゃんと聞いていたんですね。","ENG":"Oh, so you're interested in this after all. You're not like your money-grubbing colleagues.","TWN":"噢噢，看來你是真的感興趣呀。跟那些眼裡只有錢的高利貸員工不一樣。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"제 가설은 그 유적이 우리보다 고도로 발전한 문명의 잔재라는 겁니다.","JPN":"僕の仮説によると、あの遺跡は僕らの文明よりも高度な文明の名残です。","ENG":"My hypothesis is that the ruins are remains of a highly developed civilization, even more advanced than ours.","TWN":"我的假設是，這個留下來的遺跡是比我們擁有更高度文明所留下的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"그들이 남긴 유산을 해석한다면 과학기술의 패러다임을 바꾸는 혁신도 꿈은 아닐 거예요.","JPN":"彼らが遺した遺産を解読すれば、科学技術のパラダイムを変える革新も夢ではないでしょう。","ENG":"If I can decipher what they've left behind, it could be a game changer in science and technology.","TWN":"如果解讀了他們留下的遺產，那有望改變科學技術的模式。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"많은 이들이 저를 비웃었지만...... 이번 탐사가 성공하면 누가 옳았는지 밝혀지겠죠.","JPN":"この仮説で多くの人に笑われてきましたが……今回の探査が成功すれば、誰が正しかったのか明らかになるでしょう。","ENG":"Many have scoffed at me for this... but we'll see who gets the last laugh once this expedition is a success.","TWN":"雖然有很多人嘲笑我……但只要這次探索成功，到時候就知道誰對誰錯了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"우와아......","JPN":"うわあ……","ENG":"Whoa...","TWN":"哇啊……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"왠지 가슴이 뛰네요. 꼭 성공하면 좋겠어요.","JPN":"なんだかドキドキする話ですね。ぜひ成功してほしいです。","ENG":"That's pretty exciting. I hope you find what you're looking for.","TWN":"不知為什麼聽了覺得有些激動呢，希望你能成功。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"이야, 대장. 알고 보니 우리가 교과서에 실릴 분이랑 일하고 있었네.","JPN":"いやぁ、隊長。俺たち、これから教科書に名前が載る方と一緒に働いていたとはな。","ENG":"Hey, Captain. It turns out we're working for a man who'll end up in history textbooks.","TWN":"哎呀，隊長。原來我們是在跟將來可能會出現在教科書上的人物一起工作啊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"하핫. 그러게 말이야.","JPN":"ハハハ、そうだな。","ENG":"Hah hah. I know, right?","TWN":"哈哈，就是說啊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"일이 잘 풀리면 저희도 한 줄 적어 주시는 겁니다?","JPN":"うまくいったら、論文に俺らのこともぜひ忘れず一言書いてください。","ENG":"Could you put our names in the appendix once all goes well, Doc?","TWN":"如果事情成功的話，也會給我們在書上留下記錄嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"미안하지만 그건 안 됩니다.","JPN":"悪いけど、それはできません。","ENG":"I'm afraid not.","TWN":"很抱歉，這個是不可以的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"네? 아니, 선생님. 그냥 농담인데......","JPN":"はい？　いや、先生。ただの冗談ですが……","ENG":"Sorry? Oh, Doc. I was just kidding...","TWN":"呃？那個，先生，我只是開個玩笑……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"가설을 세운 사람도 저고, 탐사를 추진한 사람도 접니다.","JPN":"仮説を立てたのは僕で、探査を推進した人も僕です。","ENG":"I'm the one who developed this hypothesis, and I'm the one who planned this expedition.","TWN":"提出假說的人是我，促成探索的人也是我。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"남의 공로를 가로채려고 하지 말고 본인이 노력하셔야죠.","JPN":"人の手柄を横取りしようとしないで、みずから努力してください。","ENG":"You shouldn't try to steal other people's work.","TWN":"不要老是想著搶別人的功勞，要自己努力才行。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"뭐? 이 양반이 사람을 뭘로 알고!","JPN":"はあ？　ちょっとバカにしすぎじゃねえか？","ENG":"What? Hey, what do you take me for?","TWN":"什麼？你把其他人當什麼了！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"자, 자. 진정해, 이 친구야. 다 웃자고 한 소리였잖아.","JPN":"まあまあ、落ち着け。冗談だし。","ENG":"Easy now. Settle down, buddy. We're all just trying to have some fun.","TWN":"好了，好了，冷靜點。不就是開個玩笑嘛。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"윌버 씨, 좀 심하셨어요. 저 분들도 가볍게 한 말일 텐데.","JPN":"ウィルバーさん、ちょっと言い過ぎじゃありませんか？　あの方たちは深く考えずに言っただけなのに。","ENG":"That was a bit harsh, Mr. Wilbur. I'm sure they meant no harm.","TWN":"韋爾伯，您有點太過分了。他們只不過是開個玩笑而已。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"아뇨. 이런 건 확실하게 선을 그어야 합니다.","JPN":"いいえ。こういうことは最初からハッキリしておかないと。","ENG":"On the contrary. You've got to draw a clear line when it comes to matters like this.","TWN":"不，這種事情可不能開玩笑。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"대시라고 했죠? 충고드리는데 당신도 그 사채업자들과 너무 가깝게 지내지 마세요.","JPN":"ダッシュさんでしたね？　忠告ですが、あなたもあの闇金業者とあまり仲良くしないほうがいいですよ。","ENG":"You said your name is Dash, right? Let me give you some advice. Don't get too close with those loan sharks.","TWN":"你叫黛西是吧？我給你個忠告，不要跟那些放高利貸的人走得太近。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"저런 것들은 상대가 조금만 약한 모습을 보이면 물어뜯기 급급한......","JPN":"あの部類の人たちは相手が少しでも弱みを見せると噛みついてくる……","ENG":"The moment you show any sign of vulnerability, they'll come right at you and tear you apart—","TWN":"那些傢伙，一旦對方露出弱點就會咬住不放……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"잠시, 할 얘기가 있다.","JPN":"しばし、話がある。","ENG":"Pray, hearken to me for a moment.","TWN":"等等，我有話要說。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"응?","JPN":"ん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"당신은 그 때 분명...... 무보수로 오겠다고 한 용병 맞죠?","JPN":"あなたはあの時確か……無報酬で参加すると言った傭兵ですよね？","ENG":"Aren't you that mercenary... who agreed to come free of charge?","TWN":"你是那個……不要報酬的，對吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"설마 이제 와서 보수를 달라고 하려는 겁니까?","JPN":"もしかして、今更報酬が欲しくなったのですか？","ENG":"Did you change your mind or something?","TWN":"不會是，現在又想要報酬了吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저어...... 왜 그러세요, 모르스 씨?","JPN":"あの……どうかしましたか、モールスさん？","ENG":"Um... What's wrong, Ms. Mors?","TWN":"那個……有什麼事嗎，莫爾斯？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"무기를 들어라. 남겨진 자들이 오는도다.","JPN":"武器を持て。残された者が近付いてくる。","ENG":"Draw your weapons. The Remaining Ones approach.","TWN":"拿起武器。剩下的人過來。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"남겨진 자들이요?","JPN":"残された者？","ENG":"The Remaining Ones?","TWN":"剩下的人？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"으앙!?","JPN":"ええっ！？","ENG":"Huh?!","TWN":"呃啊！？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_BOOM_REPEAT"},{"id":"L10_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"고, 공격이에요! 공격 받고 있어요! 말로만 듣던 스캐빈저 놈들이면 어떡해요!?","JPN":"こ、攻撃です！　攻撃されています！　噂のスカベンジャーだったらどうしましょう！？","ENG":"W-we're under attack! We're under attack! What if its those notorious Scavengers I've heard of?","TWN":"攻、攻擊！被攻擊了！如果是傳聞中的清道夫的話怎麼辦啊！？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"내 자료......! 내 자료들을 노리고 온 거야! 안 돼!","JPN":"僕の資料……！　資料を狙ってきたのか！　絶対に渡さない！","ENG":"My research... They must be after my research! No!","TWN":"我的資料……！是衝著我的資料來的！不行！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"앗, 윌버 씨?!","JPN":"あっ、ウィルバーさん！？","ENG":"Mr. Wilbur?!","TWN":"啊，韋爾伯？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"대장! 밖을 봐! 침식체가 새카맣게 몰려들었어!","JPN":"隊長、外を！　えらい数の侵食体が襲いかかって来てるぞ！","ENG":"Captain! Look outside! There's a whole swarm of C.O.s coming at us!","TWN":"隊長！看外面！侵蝕體黑壓壓地湧過來了！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"큭...... 저렇게 가까이 왔는데 왜 아무런 경고도 없었던 거야?","JPN":"くっ……ここまで近付いてきてるのに、なぜ何の警告もなかったんだ？","ENG":"Ugh... There was no early warning; how did they manage to get so close?","TWN":"呃……已經這麼靠近了，為什麼一點警告聲都沒有？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"다들 갑판 위로 간다! 수송선이 침몰하면 우린 전부 끝장이야!","JPN":"みんな、甲板に向かえ！　輸送船が沈没したら俺ら全員終わりだ！","ENG":"Everyone, hit the deck! If the ship sinks, we'll be done for!","TWN":"大家都到甲板上去！運輸船沉沒的話我們就都完了！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"어, 어쩌지? 언니가 설치지 말랬는데?","JPN":"ど、どうしよう？　リタお姉ちゃんに大人しくしてって言われたけど……","ENG":"W-what should I do? Rita said I should stay put...","TWN":"怎、怎麼辦？姐姐有警告我千萬不可以闖禍的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그치만 침식체들이랑 싸우다가 용병 아저씨들이 다치기라도 하면......","JPN":"でも侵食体と戦って傭兵のおじさんたちが怪我でもしたら……","ENG":"But what if the mercenaries get hurt fighting the C.O.s?","TWN":"但是傭兵叔叔們跟侵蝕體戰鬥時受傷的話……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"잠시만요! 저도 같이 싸울래요! 같이 가요!","JPN":"待ってください！　私も戦います！　一緒に行きましょう！","ENG":"Wait! I'll fight with you! Let me tag along!","TWN":"等等！我也要一起戰鬥！一起走吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};